import React, { useState, useEffect, useMemo, useRef } from "react";
import { ArrowRight } from "lucide-react";
import heroKitchen from "../../images/upscaledherokitchen.png";

const HERO_BG = heroKitchen;

// --- THE HERO ANIMATED COUNTER ---
const AnimatedCounter = ({ text }) => {
  const [count, setCount] = useState(0);
  const [hasStarted, setHasStarted] = useState(false);
  const counterRef = useRef(null);

  const match = useMemo(() => text.match(/^(\D*)(\d+)(\D*)$/), [text]);

  useEffect(() => {
    if (!match) return;

    let hasTriggered = false;
    const target = parseInt(match[2], 10);
    const duration = 2000;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && !hasTriggered) {
          hasTriggered = true;

          // Waits 1200ms to allow the gentle typographic reveal to finish first
          setTimeout(() => {
            setHasStarted(true);
            let startTimestamp = null;

            const step = (timestamp) => {
              if (!startTimestamp) startTimestamp = timestamp;
              const progress = Math.min((timestamp - startTimestamp) / duration, 1);

              const easeOut = progress === 1 ? 1 : 1 - Math.pow(2, -10 * progress);
              setCount(Math.floor(easeOut * target));

              if (progress < 1) {
                window.requestAnimationFrame(step);
              }
            };
            window.requestAnimationFrame(step);
          }, 1200);

          if (counterRef.current) observer.disconnect();
        }
      },
      { threshold: 0.1 }
    );

    if (counterRef.current) observer.observe(counterRef.current);

    return () => observer.disconnect();
  }, [match]);

  if (!match) return <span>{text}</span>;

  return (
    <span ref={counterRef}>
      {match[1]}
      {hasStarted ? count : 0}
      {match[3]}
    </span>
  );
};
// ------------------------------------

export default function Hero() {
  const parallaxRef = useRef(null);
  const [isLoaded, setIsLoaded] = useState(false);

  // 1. TRIGGER ENTRANCE ANIMATION ON MOUNT
  useEffect(() => {
    const timer = setTimeout(() => setIsLoaded(true), 100);
    return () => clearTimeout(timer);
  }, []);

  // 2. THE LERP PARALLAX SCROLL LOOP
  useEffect(() => {
    let animationFrameId;
    let currentY = 0;
    let targetY = 0;

    const handleScroll = () => {
      targetY = Math.max(0, window.scrollY) * 0.4;
    };

    window.addEventListener("scroll", handleScroll, { passive: true });

    const render = () => {
      currentY += (targetY - currentY) * 0.1;
      if (parallaxRef.current) {
        parallaxRef.current.style.transform = `translateY(${currentY.toFixed(2)}px)`;
      }
      animationFrameId = window.requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener("scroll", handleScroll);
      window.cancelAnimationFrame(animationFrameId);
    };
  }, []);

  const scrollTo = (e, href) => {
    e.preventDefault();
    const el = document.querySelector(href);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <section
      id="top"
      data-testid="hero-section"
      className="relative min-h-[100svh] w-full flex items-end overflow-hidden bg-brand-ink"
    >
      <img
        ref={parallaxRef}
        src={HERO_BG}
        alt="Modern architectural home exterior at twilight"
        className="absolute inset-0 w-full h-full object-cover opacity-90 scale-105 origin-top"
        style={{ willChange: "transform" }}
      />

      <div
        className="absolute inset-0"
        style={{
          background:
            "linear-gradient(180deg, rgba(0,0,0,0.55) 0%, rgba(0,0,0,0.40) 45%, rgba(0,0,0,0.85) 100%)",
        }}
      />

      <div className="relative z-10 w-full max-w-7xl mx-auto px-6 md:px-10 pb-20 md:pb-28 pt-32">
        <div className="max-w-4xl reveal">

          {/* Eyebrow Reveal */}
          <div
            className={`flex items-center gap-3 mb-8 transition-all duration-[1500ms] ease-out ${isLoaded ? "opacity-100 translate-y-0" : "opacity-0 translate-y-6"}`}
            data-testid="hero-eyebrow"
          >
            <span className="block w-10 h-px bg-brand-accent" />
            <span className="text-xs tracking-[0.28em] uppercase text-white/70 font-medium">
              Sunwest Builds &mdash; Est. Toronto
            </span>
          </div>

          {/* THE ELEGANT FADE & DRIFT HEADLINE REVEAL */}
          <h1
            data-testid="hero-headline"
            className="font-display text-[2.75rem] leading-[1.05] sm:text-6xl md:text-7xl lg:text-[5.5rem] font-medium text-white tracking-tighter"
          >
            <span className={`block transition-all duration-[1500ms] delay-150 ease-out ${isLoaded ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"}`}>
              Commercial-Grade Precision.
            </span>
            <span className={`block text-white/70 transition-all duration-[1500ms] delay-300 ease-out pb-1 md:pb-3 ${isLoaded ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"}`}>
              Residential Care.
            </span>
          </h1>

          {/* Subheadline Reveal */}
          <p
            data-testid="hero-subheadline"
            className={`mt-6 md:mt-8 max-w-2xl text-lg md:text-xl leading-relaxed text-white/80 font-light transition-all duration-[1500ms] delay-500 ease-out ${isLoaded ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"}`}
          >
            Bringing over a decade of enterprise high-rise and development
            management to premium custom residential builds.
          </p>

          {/* Buttons Reveal */}
          <div className={`mt-10 md:mt-12 flex flex-wrap items-center gap-4 transition-all duration-[1500ms] delay-700 ease-out ${isLoaded ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"}`}>
            <a
              href="#contact"
              onClick={(e) => scrollTo(e, "#contact")}
              data-testid="hero-cta-primary"
              className="cta-accent group inline-flex items-center gap-3 bg-brand-accent hover:bg-brand-accentHover text-white px-8 py-4 text-sm font-medium tracking-wide transition-colors"
            >
              Start Your Project
              <ArrowRight
                size={18}
                className="transition-transform duration-300 group-hover:translate-x-1"
              />
            </a>
            <a
              href="#projects"
              onClick={(e) => scrollTo(e, "#projects")}
              data-testid="hero-cta-secondary"
              className="inline-flex items-center gap-3 text-white/90 hover:text-white text-sm font-medium tracking-wide border-b border-white/30 hover:border-brand-accent transition-colors pb-1"
            >
              View Our Work
            </a>
          </div>
        </div>

        {/* Stats Reveal */}
        <div
          className={`mt-20 md:mt-28 border-t border-white/15 pt-6 grid grid-cols-2 md:grid-cols-4 gap-6 transition-all duration-[1500ms] delay-1000 ease-out ${isLoaded ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"}`}
          data-testid="hero-stat-strip"
        >
          {[
            ["10+", "Years on site"],
            ["$50M+", "Budgets managed"],
            ["High-rise", "Enterprise pedigree"],
            ["Custom", "Residential focus"],
          ].map(([k, v]) => (
            <div key={v} className="flex flex-col">
              <span className="font-display text-2xl md:text-3xl text-white font-medium">
                <AnimatedCounter text={k} />
              </span>
              <span className="text-xs uppercase tracking-widest text-white/55 mt-1">
                {v}
              </span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
